-- Item-related reference tables migrated from MSSQL
-- Tables: item_op, set_item, monster_item, item_exchange,
--         item_upgrade_settings, new_upgrade
-- Data counts: item_op(2,703), set_item(1,165), monster_item(2,154),
--   item_exchange(5,023), item_upgrade_settings(257), new_upgrade(18,148)

-----------------------------------------------
-- item_op: Item special effects / triggered skills
-- MSSQL source: ITEM_OP (2,703 rows)
-- C++ Reference: ItemTableSet.h _ITEM_OP
-----------------------------------------------
CREATE TABLE IF NOT EXISTS item_op (
    item_id        INTEGER   NOT NULL,
    trigger_type   SMALLINT  DEFAULT 0,
    skill_id       INTEGER   DEFAULT 0,
    trigger_rate   SMALLINT  DEFAULT 0
);
CREATE INDEX idx_item_op_item_id ON item_op (item_id);

