-----------------------------------------------
-- set_item: Set item bonuses (wearing full set grants extra stats)
-- MSSQL source: SET_ITEM (1,165 rows)
-- C++ Reference: ItemTableSet.h _SET_ITEM
-----------------------------------------------
CREATE TABLE IF NOT EXISTS set_item (
    set_index              INTEGER   NOT NULL PRIMARY KEY,
    set_name               VARCHAR(255),
    ac_bonus               SMALLINT  DEFAULT 0,
    hp_bonus               SMALLINT  DEFAULT 0,
    mp_bonus               SMALLINT  DEFAULT 0,
    strength_bonus         SMALLINT  DEFAULT 0,
    stamina_bonus          SMALLINT  DEFAULT 0,
    dexterity_bonus        SMALLINT  DEFAULT 0,
    intel_bonus            SMALLINT  DEFAULT 0,
    charisma_bonus         SMALLINT  DEFAULT 0,
    flame_resistance       SMALLINT  DEFAULT 0,
    glacier_resistance     SMALLINT  DEFAULT 0,
    lightning_resistance   SMALLINT  DEFAULT 0,
    poison_resistance      SMALLINT  DEFAULT 0,
    magic_resistance       SMALLINT  DEFAULT 0,
    curse_resistance       SMALLINT  DEFAULT 0,
    xp_bonus_percent       SMALLINT  DEFAULT 0,
    coin_bonus_percent     SMALLINT  DEFAULT 0,
    ap_bonus_percent       SMALLINT  DEFAULT 0,
    ap_bonus_class_type    SMALLINT  DEFAULT 0,
    ap_bonus_class_percent SMALLINT  DEFAULT 0,
    ac_bonus_class_type    SMALLINT  DEFAULT 0,
    ac_bonus_class_percent SMALLINT  DEFAULT 0,
    max_weight_bonus       SMALLINT  DEFAULT 0,
    np_bonus               SMALLINT  DEFAULT 0,
    unk1                   SMALLINT  DEFAULT 0,
    unk2                   SMALLINT  DEFAULT 0,
    unk3                   SMALLINT  DEFAULT 0,
    unk4                   SMALLINT  DEFAULT 0,
    unk5                   SMALLINT  DEFAULT 0,
    unk6                   SMALLINT  DEFAULT 0,
    unk7                   SMALLINT  DEFAULT 0,
    unk8                   SMALLINT  DEFAULT 0,
    unk9                   SMALLINT  DEFAULT 0,
    unk10                  SMALLINT  DEFAULT 0,
    unk11                  SMALLINT  DEFAULT 0,
    unk12                  SMALLINT  DEFAULT 0,
    unk13                  SMALLINT  DEFAULT 0,
    unk14                  SMALLINT  DEFAULT 0
);

