-----------------------------------------------
-- item_upgrade_settings: Upgrade material requirements and success rates
-- MSSQL source: ITEM_UPGRADE_SETTINGS (257 rows)
-- C++ Reference: ItemTableSet.h, CGameServerDlg::LoadItemUpgradeTable()
-----------------------------------------------
CREATE TABLE IF NOT EXISTS item_upgrade_settings (
    req_item_id1   INTEGER      DEFAULT 0,
    req_item_name1 VARCHAR(100),
    req_item_id2   INTEGER      DEFAULT 0,
    req_item_name2 VARCHAR(100),
    upgrade_note   VARCHAR(200),
    item_type      SMALLINT     DEFAULT 0,
    item_rate      SMALLINT     DEFAULT 0,
    item_grade     SMALLINT     DEFAULT 0,
    item_req_coins INTEGER      DEFAULT 0,
    success_rate   SMALLINT     DEFAULT 0
);
CREATE INDEX idx_item_upgrade_type_rate_grade ON item_upgrade_settings (item_type, item_rate, item_grade);

ON CONFLICT DO NOTHING;

ON CONFLICT DO NOTHING;
-----------------------------------------------
-- new_upgrade: Item upgrade transformation recipes
-- MSSQL source: NEW_UPGRADE1 (18,148 rows)
-- C++ Reference: ItemTableSet.h _NEW_UPGRADE
-----------------------------------------------
CREATE TABLE IF NOT EXISTS new_upgrade (
    n_index        INTEGER   NOT NULL PRIMARY KEY,
    str_note       VARCHAR(100),
    origin_number  INTEGER   DEFAULT 0,
    n_str_note     VARCHAR(100),
    new_number     INTEGER   DEFAULT 0,
    req_item       INTEGER   DEFAULT 0,
    grade          SMALLINT  DEFAULT 0
);
CREATE INDEX idx_new_upgrade_origin ON new_upgrade (origin_number);

